import datasets
import numpy as np
from scipy.optimize import curve_fit

ds = datasets.load_from_disk('/app/data')
df = ds.to_pandas()

x_data = (df['non_vocab_parameters'].values, df['num_characters'].values, df['vocab_size'].values)
y_data = df['unigram_normalized_loss'].values

def m1(x, A, alpha, B, beta, E):
    N, D, V = x
    return A * (N**-alpha) + B * ((D/V)**-beta) + E

def m2(x, A, alpha, B, beta, E):
    N, D, V = x
    return A * ((N/V)**-alpha) + B * ((D/V)**-beta) + E

def m3(x, A, alpha, B, beta, gamma, E):
    N, D, V = x
    return A * (N**-alpha) + B * ((D/(V**gamma))**-beta) + E

def m4(x, A, alpha, B, beta, gamma, E):
    N, D, V = x
    return A * (N**-alpha) + B * (D**-beta) + gamma * np.log(V) + E

for i, (name, m) in enumerate([('D/V', m1), ('N/V, D/V', m2), ('D/V^gamma', m3), ('log(V)', m4)]):
    try:
        if i < 2:
            p0 = [100, 0.3, 100, 0.3, -5]
        elif i == 2:
            p0 = [100, 0.3, 100, 0.3, 1.0, -5]
        else:
            p0 = [100, 0.3, 100, 0.3, 0.1, -5]
        popt, _ = curve_fit(m, x_data, y_data, p0=p0, maxfev=10000)
        mse = np.mean((y_data - m(x_data, *popt))**2)
        print(f"Model {name} MSE: {mse:.6f}")
        print(f"Params: {popt}\n")
    except Exception as e:
        print(f"Model {name} failed: {e}\n")
