import numpy as np

N_values = [33222784.0, 84834176.0, 150834176.0, 316445568.0, 631668352.0, 1129891136.0]

# Typical transformer non-vocab params:
# N = n_layers * (12 * d_model**2 + 13 * d_model) + 2 * d_model + max_seq_len * d_model
# Let's assume max_seq_len = 1024 or 2048

for N in N_values:
    found = False
    for seq_len in [512, 1024, 2048, 4096]:
        for d_model in range(64, 4097, 64):
            # Solve for n_layers
            # N - 2*d_model - seq_len*d_model = n_layers * (12*d_model**2 + 13*d_model)
            remainder = N - 2*d_model - seq_len*d_model
            per_layer = 12 * d_model**2 + 13 * d_model
            if remainder % per_layer == 0:
                n_layers = remainder // per_layer
                if n_layers > 0:
                    print(f"N={N}: d_model={d_model}, n_layers={n_layers}, seq_len={seq_len}")
                    found = True
    if not found:
        print(f"N={N}: No standard architecture found.")
